(function(){'use strict';const Performance ={lazyLoadImages(){if('IntersectionObserver' in window){const imageObserver = new IntersectionObserver((entries,observer)=>{entries.forEach(entry =>{if(entry.isIntersecting){const img = entry.target;img.src = img.dataset.src;img.classList.add('loaded');observer.unobserve(img);}});});document.querySelectorAll('img[data-src]').forEach(img =>{imageObserver.observe(img);});}},prefetchLinks(){document.querySelectorAll('a[href^="/"]').forEach(link =>{link.addEventListener('mouseenter',function(){const url = this.getAttribute('href');if(url && !document.querySelector(`link[rel="prefetch"][href="${url}"]`)){const prefetch = document.createElement('link');prefetch.rel = 'prefetch';prefetch.href = url;document.head.appendChild(prefetch);}},{once:true});});},debounce(func,wait){let timeout;return function executedFunction(...args){const later =()=>{clearTimeout(timeout);func(...args);};clearTimeout(timeout);timeout = setTimeout(later,wait);};},throttle(func,limit){let inThrottle;return function(){const args = arguments;const context = this;if(!inThrottle){func.apply(context,args);inThrottle = true;setTimeout(()=> inThrottle = false,limit);}};},init(){this.lazyLoadImages();this.prefetchLinks();document.querySelectorAll('a[href^="#"]').forEach(anchor =>{anchor.addEventListener('click',function(e){const target = document.querySelector(this.getAttribute('href'));if(target){e.preventDefault();target.scrollIntoView({behavior:'smooth',block:'start'});}});});console.log('🚀 Ultra Fast System Ready!');}};if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',()=> Performance.init());}else{Performance.init();}})();